import CounterPages from "./counterPages";
import { BrowserRouter, Routes, Route, Navigate, useNavigate} from "react-router-dom";
import React, { Component } from "react";

function CounterTop(){
let navigate = useNavigate();
let state = {
    pages: [
      { id: 1, name: "page #1", way: "/page1" },
      { id: 2, name: "page #2", way: "/page2" },
    ],
    index: {value: 1},
    next: "/page2",
    back: "/page0",
  };

  //adds a page of counters
  const handleAddPage = () => {};

  //deletes selected page of counters
  const handleDeletePage = () => {};

  //cycles forward a page to the next counter
  const handleNextPage = () => {
    let index = {...state.index};
    index.value++;
    //let tempWay = state.pages[index.value -1 ].way
    // <Navigate, to={this.state.pages[this.state.index.value - 1].way}; replace={true};/>;
    //<Navigate to="/page2"></Navigate>;
    navigate('/page2');
    console.log(index);
    setState({index});
  };

  //cycles back a page to the previous counter
  const handleBackPage = () => {
    let index = {...state.index};
    index.value--;
    this.setState({index});
  };

        return(
      <BrowserRouter>
      <div>

{/* only renders 1 page at a time */}
    <Routes>
              <Route
                exact
                path={state.pages[state.index.value - 1].way}
                element={
                  <CounterPages
                    key={state.pages[state.index.value - 1].id}
                    id={state.pages[state.index.value - 1].id}
                    onAddPage={handleAddPage}
                    onDeletePage={handleDeletePage}
                    onNextPage={handleNextPage}
                    onBackPage={handleBackPage}
                    pages={state.pages}>
                  </CounterPages>
                }
              ></Route>
              </Routes>


                {/* renders every page at the same time */}
              {/* <Routes>
              {this.state.pages.map(page => <Route
                exact
                path={page.way}
                element={
                  <CounterPages
                    key={page.id}
                    id={page.id}
                    onAddPage={this.handleAddPage}
                    onDeletePage={this.handleDeletePage}
                    onNextPage={this.handleNextPage}
                    onBackPage={this.handleBackPage}
                    pages={this.state.pages}>
                  </CounterPages>
                }
              ></Route>)}
              </Routes> */}

              
            {/* {
              <CounterPages>
                id={this.state.pages[this.state.index - 1].id}
                onAddPage={this.handleAddPage}
                onDeletePage={this.handleDeletePage}
                onNextPage={this.handleNextPage}
                onBackPage={this.handleBackPage}
              </CounterPages>
            } */}
        {/* this is for loading every page at once */}
        {/* <BrowserRouter>
      {this.state.pages.map(page => <CounterPages>
        id={page.id}
        onAddPage={this.handleAddPage}
        onDeletePage={this.handleDeletePage}
        </CounterPages>)}
        </BrowserRouter> */}
      </div>
      </BrowserRouter>
    );
    
}
    export default CounterTop;
